import { ContactView } from "../view/view.js";
import { ContactModel } from "../model/model.js";

export class ContactController {
  constructor() {
    this.view = new ContactView();
    this.model = new ContactModel();

    this.view.init();
    this.view.submitForm(this.handle_contact_main_section1_form1_submit);
  }

  handle_contact_main_section1_form1_submit = (formData) => {
    return this.model
      .handle_contact_main_section1_form1_submit(formData)
      .then((res) => {
        if (res.status) {
          return Promise.resolve({ status: true });
        } else {
          return Promise.reject({ status: false });
        }
      })
      .catch((err) => {
        console.log(err);
        Promise.reject({ status: false });
      });
  };
}
